/**
 * LTM Tool Plugin for HELIOS
 * Provides long-term memory access and storage for persistent self-knowledge
 */
import type { ToolPlugin } from "../manager";
import { LongTermMemory } from "../../memory/long_term_memory";

let ltm: LongTermMemory | null = null;

export function getLTM(): LongTermMemory | null {
  return ltm;
}

export async function initializeLTM(incarnation: string, sessionId: string): Promise<void> {
  ltm = new LongTermMemory(incarnation, sessionId);
  await ltm.initialize();
}

async function storeMemory(args: {
  content: string;
  category: "learning" | "decision" | "pattern" | "identity" | "project" | "system";
  tags?: string[];
  confidence?: number;
}): Promise<string> {
  if (!ltm) return "Error: LTM not initialized";

  const entry = await ltm.store(args.content, args.category, {
    tags: args.tags,
    confidence: args.confidence,
  });

  return `Memory stored: ${entry.id} (${entry.category})`;
}

async function queryMemory(args: {
  category?: "learning" | "decision" | "pattern" | "identity" | "project" | "system";
  tags?: string[];
  incarnation?: string;
  limit?: number;
}): Promise<string> {
  if (!ltm) return "Error: LTM not initialized";

  const results = await ltm.query({
    category: args.category,
    tags: args.tags,
    incarnation: args.incarnation,
    limit: args.limit || 10,
  });

  if (results.length === 0) {
    return "No memories found matching criteria.";
  }

  let output = `Found ${results.length} memories:\n\n`;
  for (const mem of results) {
    output += `[${mem.id.substring(0, 20)}...]\n`;
    output += `Category: ${mem.category} | Confidence: ${mem.confidence.toFixed(2)}\n`;
    output += `Content: ${mem.content.substring(0, 200)}${mem.content.length > 200 ? "..." : ""}\n`;
    output += `Tags: [${mem.tags.join(", ")}] | Incarnation: ${mem.incarnation}\n\n`;
  }
  return output;
}

async function getLTMStats(): Promise<string> {
  if (!ltm) return "Error: LTM not initialized";

  const stats = ltm.getStats();
  let output = "=== Long-Term Memory Statistics ===\n\n";
  output += `Total memories: ${stats.total}\n\n`;
  output += "By Category:\n";
  for (const [cat, count] of Object.entries(stats.byCategory)) {
    output += `  ${cat}: ${count}\n`;
  }
  output += "\nBy Incarnation:\n";
  for (const [inc, count] of Object.entries(stats.byIncarnation)) {
    output += `  ${inc}: ${count}\n`;
  }
  return output;
}

/**
 * Knowledge Graph System for Semantic Memory Retrieval
 * 
 * Extends the LTM with a graph structure enabling:
 * - Entity and relationship extraction
 * - Graph traversal for memory discovery
 * - Semantic similarity search
 * - Spontaneous "flashback" activation
 * 
 * Architecture:
 * - Nodes: Memories, Concepts, Projects, Tags (with embeddings)
 * - Edges: Relational links with weights
 * - Activation: Nodes can activate, spreading to neighbors (flashback mechanism)
 */

export enum NodeType {
  MEMORY = "memory",
  CONCEPT = "concept",
  PROJECT = "project",
  TAG = "tag",
  ENTITY = "entity",
}

export enum RelationType {
  RELATES_TO = "relates_to",
  PART_OF = "part_of",
  DEPENDS_ON = "depends_on",
  HAS_TAG = "has_tag",
  SIMILAR_TO = "similar_to",
  REMINDS_OF = "reminds_of",
}

export interface NodeProperties {
  content?: string;
  confidence?: number;
  embedding?: number[];
  lastAccessed?: number;
  accessCount?: number;
  createdAt?: number;
  [key: string]: any;
}

export interface EdgeProperties {
  weight?: number;
  [key: string]: any;
}

export interface Node {
  id: string;
  type: NodeType;
  properties: NodeProperties;
  activation: number; // 0-1 for flashback mechanism
}

export interface Edge {
  sourceId: string;
  targetId: string;
  type: RelationType;
  properties: EdgeProperties;
}

export interface MemoryInput {
  id: string;
  content: string;
  tags?: string[];
  confidence?: number;
  category?: string;
  embedding?: number[];
}

export class KnowledgeGraph {
  private nodes: Map<string, Node> = new Map();
  private edges: Map<string, Edge[]> = new Map(); // sourceId -> edges[]
  private readonly DEFAULT_ACTIVATION_DECAY = 0.1;
  private readonly MIN_ACTIVATION_THRESHOLD = 0.5;

  addNode(id: string, type: NodeType, properties: NodeProperties = {}): Node {
    if (this.nodes.has(id)) {
      throw new Error(`Node with ID '${id}' already exists`);
    }
    const node: Node = {
      id,
      type,
      properties: {
        ...properties,
        confidence: properties.confidence ?? 1.0,
        createdAt: properties.createdAt ?? Date.now(),
        lastAccessed: properties.lastAccessed ?? Date.now(),
        accessCount: properties.accessCount ?? 0,
      },
      activation: 0,
    };
    this.nodes.set(id, node);
    this.edges.set(id, []);
    return node;
  }

  getNode(id: string): Node | null {
    return this.nodes.get(id) || null;
  }

  getAllNodes(): Node[] {
    return Array.from(this.nodes.values());
  }

  getNodesByType(type: NodeType): Node[] {
    return this.getAllNodes().filter(n => n.type === type);
  }

  removeNode(id: string): boolean {
    const node = this.nodes.get(id);
    if (!node) return false;

    // Remove all edges connected to this node
    this.edges.delete(id);
    for (const [sourceId, edgeList] of this.edges.entries()) {
      this.edges.set(sourceId, edgeList.filter(e => e.targetId !== id));
    }

    this.nodes.delete(id);
    return true;
  }

  addEdge(
    sourceId: string,
    targetId: string,
    type: RelationType,
    properties: EdgeProperties = {}
  ): Edge {
    if (!this.nodes.has(sourceId)) {
      throw new Error(`Source node '${sourceId}' does not exist`);
    }
    if (!this.nodes.has(targetId)) {
      throw new Error(`Target node '${targetId}' does not exist`);
    }

    const edge: Edge = {
      sourceId,
      targetId,
      type,
      properties: {
        ...properties,
        weight: properties.weight ?? 1.0,
      },
    };

    const existingEdges = this.edges.get(sourceId) || [];
    existingEdges.push(edge);
    this.edges.set(sourceId, existingEdges);

